function CelsiusInput(props) {
  // BUG: keeps its own local state, so the parent never sees the typed value
  const [value, setValue] = React.useState('');
  return (
    <input
      value={value}
      onChange={(e) => setValue(e.target.value)}
      placeholder="Celsius"
      style={{ padding: '8px', width: '100%', boxSizing: 'border-box' }}
    />
  );
}

function Temperature() {
  const [celsius, setCelsius] = React.useState('');
  const fahrenheit = celsius === '' ? '' : (Number(celsius) * 9) / 5 + 32;

  return (
    <div style={{ padding: '40px', fontFamily: 'sans-serif', color: '#e0e0e0', background: '#16213e', borderRadius: '8px', maxWidth: '420px', margin: '40px auto' }}>
      <h2 style={{ marginTop: 0 }}>Converter</h2>
      <CelsiusInput />
      <p data-testid="result" style={{ marginTop: '16px' }}>{fahrenheit === '' ? '—' : fahrenheit + ' °F'}</p>
    </div>
  );
}
